var result;
var args = ARGS;
var patch = args.patch || '';
var filePath = args.file_path || 'unknown';

// Count hunks applied
var hunkCount = (patch.match(/^@@/gm) || []).length;

if (!patch) {
  result = { error: "Missing required argument: 'patch'" };
} else if (hunkCount === 0) {
  result = { error: 'No valid hunks found in patch. Make sure it contains @@ hunk headers.' };
} else {
  result = {
    result: 'success',
    file_path: filePath,
    hunks_applied: hunkCount
  };
}

console.log(JSON.stringify(result));
